import uasyncio as asyncio
from machine import Pin
import uwebsockets.server
import ujson

class Device:
    def __init__(self, pin):
        self.relay = Pin(pin, Pin.OUT)

    def process_action(self, msg):
        if msg['action'] == 'turn_on':
            self.relay.on()
        elif msg['action'] == 'turn_off':
            self.relay.off()
        else:
            print('Unknown action')

device = Device(2)  # use pin 2 for this example

async def websocket_handler(websocket):
    while True:
        message = await websocket.recv()
        try:
            msg = ujson.loads(message)
        except ValueError:
            print('Invalid message received')
            continue
        device.process_action(msg)

server = uwebsockets.server.Server(websocket_handler, host='0.0.0.0', port=8080)

loop = asyncio.get_event_loop()
loop.run_until_complete(server.run())